import torch
import torch.nn.functional as F

def softmax_with_temperature(logits: torch.Tensor, temperature: float) -> torch.Tensor:
    return F.softmax(logits / temperature, dim=1)

def kl_divergence(p: torch.Tensor, q: torch.Tensor) -> torch.Tensor:
    eps = 1e-10
    kl = (p * torch.log((p + eps) / (q + eps))).sum(dim=1)
    return kl.mean()

def distillation_loss(
    student_logits: torch.Tensor,
    teacher_logits: torch.Tensor,
    y_true: torch.Tensor,
    temperature: float,
    alpha: float
) -> torch.Tensor:
    teacher_soft = softmax_with_temperature(teacher_logits, temperature)
    student_log_soft = F.log_softmax(student_logits / temperature, dim=1)
    soft_loss = F.kl_div(student_log_soft, teacher_soft, reduction='batchmean') * (temperature ** 2)
    hard_loss = F.cross_entropy(student_logits, y_true)
    return alpha * soft_loss + (1 - alpha) * hard_loss
